SELECT coupon_code, discount_amount
FROM coupons
WHERE coupon_id > 0;

SELECT bundle_name, bundle_description
FROM bundles
WHERE bundle_name IS NOT NULL;

SELECT COUNT(*) AS product_count
FROM products
WHERE product_id IN (SELECT product_id FROM inventory);

SELECT SUM(discount_amount) AS total_discounts
FROM order_coupons
WHERE order_coupon_id = 0;
